function Cart({ cartItems, setCartItems, setPage }) {
  const increaseQty = (id) => {
    setCartItems(
      cartItems.map((item) =>
        item.id === id ? { ...item, quantity: item.quantity + 1 } : item
      )
    );
  };

  const decreaseQty = (id) => {
    setCartItems(
      cartItems.map((item) =>
        item.id === id && item.quantity > 1
          ? { ...item, quantity: item.quantity - 1 }
          : item
      )
    );
  };

  const removeItem = (id) => {
    setCartItems(cartItems.filter((item) => item.id !== id));
  };

  const total = cartItems.reduce(
    (sum, item) => sum + item.priceNumber * item.quantity,
    0
  );

  return (
    <>
      <section className="shop-banner">
        <h1>Your Cart</h1>
      </section>

      <section className="cart-page">
        <div className="cart-left">
          {cartItems.length === 0 ? (
            <div className="empty-cart">
              <h2>Your cart is empty</h2>
              <button onClick={() => setPage("fitness")}>SHOP NOW</button>
            </div>
          ) : (
            <div className="cart-table">
              <div className="cart-head">
                <b>Product</b>
                <b>Price</b>
                <b>Quantity</b>
                <b>Subtotal</b>
              </div>

              {cartItems.map((item) => (
                <div className="cart-row" key={item.id}>
                  <button className="remove-btn" onClick={() => removeItem(item.id)}>
                    ×
                  </button>

                  <img src={item.img} alt={item.name} />

                  <h3>{item.name}</h3>

                  <p>
                    ${item.priceNumber.toFixed(2)}
                    <br />
                    <span>/ week</span>
                  </p>

                  <div className="qty-box">
                    <button onClick={() => decreaseQty(item.id)}>-</button>
                    <span>{item.quantity}</span>
                    <button onClick={() => increaseQty(item.id)}>+</button>
                  </div>

                  <p>
                    ${(item.priceNumber * item.quantity).toFixed(2)}
                    <br />
                    <span>/ week</span>
                  </p>
                </div>
              ))}

              <button className="continue-btn" onClick={() => setPage("fitness")}>
                ← CONTINUE SHOPPING
              </button>
            </div>
          )}

          <div className="delivery-box">
            <h3>🚚 Delivery & Pickup</h3>
            <p>Delivery fees and options will be calculated at checkout.</p>
          </div>
        </div>

        <div className="cart-total-box">
          <h2>Cart totals</h2>

          <div className="total-row">
            <b>Subtotal</b>
            <span>${total.toFixed(2)}</span>
          </div>

          <div className="total-row">
            <b>Total</b>
            <strong>${total.toFixed(2)}</strong>
          </div>

          <button className="checkout-btn">PROCEED TO CHECKOUT</button>

          <p>🛡 Secure Checkout</p>
          <p>🚚 Fast Delivery</p>
          <p>🔄 Flexible Rentals</p>
        </div>
      </section>
    </>
  );
}

export default Cart;
